import java.util.*;
public class App {
    static List<String> parseCSVLine(String line) {
        List<String> fields = new ArrayList<>();
        StringBuilder current = new StringBuilder();
        boolean inQuotes = false;
        for (int i = 0; i < line.length(); i++) {
            char c = line.charAt(i);
            if (c == '"') {
                if (inQuotes && i+1 < line.length() && line.charAt(i+1) == '"') {
                    current.append('"'); i++;
                } else inQuotes = !inQuotes;
            } else if (c == ',' && !inQuotes) {
                fields.add(current.toString()); current.setLength(0);
            } else current.append(c);
        }
        fields.add(current.toString());
        return fields;
    }
    public static void main(String[] args) {
        List<String> cols = parseCSVLine("\"Smith, John\",Engineering,95000");
        System.out.println("Fields: " + cols.size());
        System.out.println("Field 0: " + cols.get(0));
        System.out.println("Field 1: " + cols.get(1));
        System.out.println("Field 2: " + cols.get(2));
    }
}

