import java.io.*;
import java.nio.file.*;
import java.util.*;
public class App {
    static String toCSVField(String value) {
        if (value == null) return "";
        boolean needsQuoting = value.contains(",") || value.contains("\"") || value.contains("\n");
        if (!needsQuoting) return value;
        return "\"" + value.replace("\"", "\"\"") + "\"";
    }
    public static void main(String[] args) throws Exception {
        Path csv = Path.of("products.csv");
        try (PrintWriter pw = new PrintWriter(new BufferedWriter(new FileWriter(csv.toFile())))) {
            pw.println("name,price,description");
            pw.printf("%s,%s,%s%n", toCSVField("Wireless Mouse, 2.4GHz"), "799", toCSVField("Compact design"));
            pw.printf("%s,%s,%s%n", toCSVField("Dell 27\" Monitor"), "18999", toCSVField("4K, HDMI"));
            pw.printf("%s,%s,%s%n", toCSVField("USB Hub"), "499", toCSVField("7-port"));
        }
        Files.readAllLines(csv).forEach(System.out::println);
    }
}

