import com.fasterxml.jackson.databind.node.*;
import java.io.*;
import java.nio.file.*;
import java.util.*;
public class App {
    static List<String> parseCSVLine(String line) {
        List<String> f = new ArrayList<>(); StringBuilder c = new StringBuilder(); boolean inQ = false;
        for (int i = 0; i < line.length(); i++) {
            char ch = line.charAt(i);
            if (ch == '"') { if (inQ && i+1 < line.length() && line.charAt(i+1) == '"') { c.append('"'); i++; } else inQ = !inQ; }
            else if (ch == ',' && !inQ) { f.add(c.toString()); c.setLength(0); }
            else c.append(ch);
        } f.add(c.toString()); return f;
    }
    public static void main(String[] args) throws Exception {
        Path csv = Path.of("products.csv");
        Files.writeString(csv, "name,category,price\nMouse,Electronics,799\nKeyboard,Electronics,1999\n\"USB Hub, 7-port\",Accessories,499\nMonitor,Electronics,18999");

        ObjectMapper mapper = new ObjectMapper();
        ArrayNode products = mapper.createArrayNode();
        String[] headers;
        try (BufferedReader br = Files.newBufferedReader(csv)) {
            headers = parseCSVLine(br.readLine()).toArray(new String[0]);
            String line;
            while ((line = br.readLine()) != null) {
                List<String> cols = parseCSVLine(line);
                ObjectNode node = mapper.createObjectNode();
                for (int i = 0; i < headers.length && i < cols.size(); i++)
                    node.put(headers[i], cols.get(i));
                products.add(node);
            }
        }
        Path jsonFile = Path.of("products.json");
        Files.writeString(jsonFile, mapper.writerWithDefaultPrettyPrinter().writeValueAsString(products));
        System.out.println("Converted " + products.size() + " products to JSON");
        System.out.println("JSON preview: " + mapper.writeValueAsString(products).substring(0, 60) + "...");
    }
