import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.node.*;
import java.io.*;
import java.nio.file.*;
import java.util.*;
import java.util.stream.*;
public class App {
    static List<String> parseLine(String line) {
        List<String> f = new ArrayList<>(); StringBuilder c = new StringBuilder(); boolean inQ = false;
        for (int i=0;i<line.length();i++) { char ch=line.charAt(i);
            if(ch=='"'){if(inQ&&i+1<line.length()&&line.charAt(i+1)=='"'){c.append('"');i++;}else inQ=!inQ;}
            else if(ch==','&&!inQ){f.add(c.toString());c.setLength(0);}else c.append(ch);}
        f.add(c.toString()); return f;
    }
    public static void main(String[] args) throws Exception {
        Path csv = Path.of("orders.csv");
        Files.writeString(csv, "orderId,product,qty,price\nORD-1,Mouse,2,799\nORD-2,Keyboard,1,1999\nORD-3,Mouse,1,799\nORD-4,Monitor,1,18999\nORD-5,Mouse,3,799\nORD-6,Keyboard,1,1999");

        Map<String, Long> productCount = new LinkedHashMap<>();
        Map<String, Long> productRevenue = new LinkedHashMap<>();
        long totalRevenue = 0; int totalOrders = 0;

        try (BufferedReader br = Files.newBufferedReader(csv)) {
            br.readLine();
            String line;
            while ((line = br.readLine()) != null) {
                List<String> cols = parseLine(line);
                String product = cols.get(1);
                long qty = Long.parseLong(cols.get(2));
                long price = Long.parseLong(cols.get(3));
                long revenue = qty * price;
                productCount.merge(product, qty, Long::sum);
                productRevenue.merge(product, revenue, Long::sum);
                totalRevenue += revenue; totalOrders++;
            }
        }
        String topProduct = productCount.entrySet().stream()
            .max(Map.Entry.comparingByValue()).map(Map.Entry::getKey).orElse("?");

        ObjectMapper mapper = new ObjectMapper();
        ObjectNode summary = mapper.createObjectNode();
        summary.put("totalOrders", totalOrders);
        summary.put("totalRevenue", totalRevenue);
        summary.put("topProduct", topProduct);
        ObjectNode byProduct = mapper.createObjectNode();
        productCount.forEach((k, v) -> byProduct.put(k, v));
        summary.set("byProduct", byProduct);
        Files.writeString(Path.of("summary.json"), mapper.writerWithDefaultPrettyPrinter().writeValueAsString(summary));

        System.out.println("Orders processed: " + totalOrders);
        System.out.println("Total revenue: ₹" + totalRevenue);
        System.out.println("Top product: " + topProduct + " (" + productCount.get(topProduct) + " orders)");
        System.out.println("JSON written.");
    }
}

