public class App {
    static String q(String v) {
        if (v == null) return "";
        if (!v.contains(",") && !v.contains("\"")) return v;
        return "\"" + v.replace("\"", "\"\"") + "\"";
    }
    public static void main(String[] args) throws Exception {
        String json = "[" +
            "{\"name\":\"Aisha\",\"department\":\"Engineering\",\"salary\":95000,\"notes\":\"Team lead\"}," +
            "{\"name\":\"Raj\",\"department\":\"Sales\",\"salary\":72000,\"notes\":\"Top performer, Q4\"}," +
            "{\"name\":\"Priya\",\"department\":\"Engineering\",\"salary\":88000,\"notes\":\"Works on \\\"auth\\\" module\"}" +
            "]";
        ObjectMapper mapper = new ObjectMapper();
        JsonNode arr = mapper.readTree(json);

        Path csv = Path.of("employees.csv");
        try (PrintWriter pw = new PrintWriter(new BufferedWriter(new FileWriter(csv.toFile())))) {
            pw.println("name,department,salary,notes");
            for (JsonNode emp : arr) {
                pw.printf("%s,%s,%s,%s%n",
                    q(emp.path("name").asText()),
                    q(emp.path("department").asText()),
                    q(emp.path("salary").asText()),
                    q(emp.path("notes").asText()));
            }
        }
        Files.readAllLines(csv).forEach(System.out::println);
    }
}

