import java.io.*;
import java.nio.file.*;
import java.util.*;
public class App {
    static List<String> parseLine(String line) {
        List<String> f=new ArrayList<>(); StringBuilder c=new StringBuilder(); boolean inQ=false;
        for(int i=0;i<line.length();i++){char ch=line.charAt(i);
            if(ch=='"'){if(inQ&&i+1<line.length()&&line.charAt(i+1)=='"'){c.append('"');i++;}else inQ=!inQ;}
            else if(ch==','&&!inQ){f.add(c.toString());c.setLength(0);}else c.append(ch);}
        f.add(c.toString());return f;
    }
    static String q(String v) { return v.contains(",")||v.contains("\"") ? "\""+v.replace("\"","\"\"")+"\"" : v; }

    public static void main(String[] args) throws Exception {
        Path f1=Path.of("file1.csv"), f2=Path.of("file2.csv");
        Files.writeString(f1, "sku,name,price\nSKU-001,Mouse,799\nSKU-002,Keyboard,1999\nSKU-003,USB Hub,499");
        Files.writeString(f2, "sku,name,price\nSKU-002,Keyboard Pro,2499\nSKU-004,Monitor,18999\nSKU-005,Webcam,4999");

        Map<String, String[]> merged = new LinkedHashMap<>();
        for (Path file : new Path[]{f1, f2}) {
            try (BufferedReader br = Files.newBufferedReader(file)) {
                br.readLine();
                String line; int count = 0;
                while ((line = br.readLine()) != null) {
                    List<String> cols = parseLine(line);
                    merged.put(cols.get(0), cols.toArray(new String[0]));
                    count++;
                }
                System.out.println((file == f1 ? "File 1" : "File 2") + " rows: " + count);
            }
        }
        Path out = Path.of("merged.csv");
        try (PrintWriter pw = new PrintWriter(new BufferedWriter(new FileWriter(out.toFile())))) {
            pw.println("sku,name,price");
            merged.values().forEach(cols -> pw.printf("%s,%s,%s%n", q(cols[0]), q(cols[1]), q(cols[2])));
        }
        System.out.println("Unique SKUs after merge: " + merged.size());
        System.out.println("Merged CSV written.");
    }
}

