import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.node.*;
import java.io.*;
import java.nio.file.*;
import java.util.*;
public class App {
    static List<String> pl(String line) {
        List<String> f=new ArrayList<>(); StringBuilder c=new StringBuilder(); boolean q=false;
        for(int i=0;i<line.length();i++){char ch=line.charAt(i);
            if(ch=='"'){if(q&&i+1<line.length()&&line.charAt(i+1)=='"'){c.append('"');i++;}else q=!q;}
            else if(ch==','&&!q){f.add(c.toString());c.setLength(0);}else c.append(ch);}
        f.add(c.toString());return f;
    }
    static String tier(double price) {
        return price > 5000 ? "PREMIUM" : price > 1000 ? "STANDARD" : "BUDGET";
    }
    public static void main(String[] args) throws Exception {
        Path csv = Path.of("inventory.csv");
        Files.writeString(csv,
            "sku,name,qty,price\n" +
            "P001,Mouse,50,799\n" +
            "P002,\"Mechanical Keyboard, RGB\",10,2499\n" +
            "P003,,5,1299\n" +  // invalid: blank name
            "P004,Monitor,2,18999\n" +
            "P005,USB Hub,-1,499\n" +  // invalid: negative qty
            "P006,Headphones,15,3999");

        ObjectMapper mapper = new ObjectMapper();
        ArrayNode validJson = mapper.createArrayNode();
        List<String> errors = new ArrayList<>();
        errors.add("sku,name,qty,price,error");

        Map<String, Long> tierCount = new HashMap<>();
        long totalValue = 0;

        try (BufferedReader br = Files.newBufferedReader(csv)) {
            br.readLine();
            String line;
            while ((line = br.readLine()) != null) {
                List<String> cols = pl(line);
                String sku = cols.get(0), name = cols.get(1);
                int qty; double price;
                try { qty=Integer.parseInt(cols.get(2)); price=Double.parseDouble(cols.get(3)); }
                catch (NumberFormatException e) { errors.add(line + ",invalid number"); continue; }

                if (name.isBlank()) { errors.add(line + ",blank name"); continue; }
                if (qty <= 0) { errors.add(line + ",invalid qty"); continue; }

                long val = (long)(qty * price);
                totalValue += val;
                String t = tier(price);
                tierCount.merge(t, 1L, Long::sum);

                ObjectNode n = mapper.createObjectNode();
                n.put("sku",sku).put("name",name).put("qty",qty)
                 .put("price",price).put("totalValue",val).put("tier",t);
                validJson.add(n);
            }
        }
        Files.writeString(Path.of("valid.json"),
            mapper.writerWithDefaultPrettyPrinter().writeValueAsString(validJson));
        Files.write(Path.of("errors.csv"), errors);

        int valid = validJson.size(), invalid = errors.size() - 1;
        System.out.println("Valid: " + valid + " | Invalid: " + invalid);
        System.out.println("Total inventory value: ₹" + totalValue);
        System.out.println("PREMIUM: " + tierCount.getOrDefault("PREMIUM",0L) +
            ", STANDARD: " + tierCount.getOrDefault("STANDARD",0L) +
            ", BUDGET: " + tierCount.getOrDefault("BUDGET",0L));
        System.out.println("Files written.");
    }
}
